namespace sv_6d6a32cda2064f8e8785c50cc7fd103e.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_6d6a32cda2064f8e8785c50cc7fd103e.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="d-flex flex-row">
        @* ── Left Sidebar ── *@
        <div class="pe-4" style="min-width:25%;max-width:25%;">
            <div class="card">
                <div class="card-header fw-semibold">Filters</div>
                <div class="card-body">
                    @* Categories *@
                    <h6>Category</h6>
                    @if (_categories is null)
                    {
                        <p class="text-muted small">Loading…</p>
                    }
                    else
                    {
                        @foreach (var cat in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                       checked="@(_selectedCategories.Contains(cat))"
                                       @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                            </div>
                        }
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Min Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_minPrice" @bind:event="onchange" placeholder="0.00" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Max Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_maxPrice" @bind:event="onchange" placeholder="No limit" />
                    </div>

                    <hr />

                    @* In-stock *@
                    <div class="form-check form-switch mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </div>

        @* ── Main Content ── *@
        <div style="flex:1;min-width:0;">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <span class="ms-3">Loading products…</span>
                </div>
            }
            else if (_result is not null)
            {
                @* Toolbar *@
                <div class="d-flex justify-content-between align-items-center mb-3">
                    <div class="d-flex align-items-center gap-2">
                        <label class="form-label mb-0 text-nowrap fw-semibold">Sort by:</label>
                        <select class="form-select form-select-sm" style="width:auto;"
                                @bind="_sortBy" @bind:after="OnSortChangedAsync">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A-Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted small">
                        @ShowingLabel()
                    </span>
                </div>

                @if (_result.Items.Count == 0)
                {
                    <div class="alert alert-info text-center" role="alert">
                        No products match your filters. Try adjusting your criteria.
                    </div>
                }
                else
                {
                    @* Product grid *@
                    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3 mb-4">
                        @foreach (var product in _result.Items)
                        {
                            <div class="col">
                                <ProductCard Product="product"
                                             OnProductSelected="OnProductSelected"
                                             OnAddToCart="OnAddToCart" />
                            </div>
                        }
                    </div>

                    @* Pagination *@
                    @if (TotalPages > 1)
                    {
                        <nav aria-label="Product pagination">
                            <ul class="pagination justify-content-center">
                                <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                            disabled="@(_currentPage == 1)">
                                        Previous
                                    </button>
                                </li>
                                @for (int i = 1; i <= TotalPages; i++)
                                {
                                    var pageNum = i;
                                    <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                        <button class="page-link" @onclick="() => GoToPageAsync(pageNum)">
                                            @pageNum
                                        </button>
                                    </li>
                                }
                                <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                            disabled="@(_currentPage == TotalPages)">
                                        Next
                                    </button>
                                </li>
                            </ul>
                        </nav>
                    }
                }
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 9;

    // Filter state
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    // Search state
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);

            var searchTask = ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
        MinPrice: _minPrice,
        MaxPrice: _maxPrice,
        InStockOnly: _inStockOnly
    );

    private void ToggleCategory(string category, bool selected)
    {
        if (selected)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        _sortBy = "price_asc";
        await SearchAsync();
    }

    private async Task OnSortChangedAsync()
    {
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > TotalPages) return;
        _currentPage = page;
        await SearchAsync();
    }

    private async Task SearchAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _result = await ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryAsync() => await LoadDataAsync();

    private string ShowingLabel()
    {
        if (_result is null || _result.TotalCount == 0) return "No products";
        var start = (_result.Page - 1) * _result.PageSize + 1;
        var end = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
        return $"Showing {start}–{end} of {_result.TotalCount} products";
    }

    private void OnProductSelected(Product product)
    {
        // Parent-level hook — navigate to detail page
        // NavigationManager.NavigateTo($"/product/{product.Id}");
    }

    private void OnAddToCart(Product product)
    {
        // Add-to-cart logic placeholder
    }
}

@using sv_6d6a32cda2064f8e8785c50cc7fd103e.Services

<div class="card h-100 shadow-sm product-card" role="button" @onclick="OnCardClicked" style="cursor:pointer;">
    @* Placeholder image *@
    <div class="bg-light d-flex align-items-center justify-content-center"
         style="height:180px;" role="img" aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>

    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" title="@($"Rating: {Product.Rating:F1} / 5")">@RenderStars(Product.Rating)</p>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <div class="mt-auto">
            <button class="btn btn-sm btn-success w-100"
                    disabled="@(!Product.InStock)"
                    @onclick="OnAddToCartClicked"
                    @onclick:stopPropagation="true">
                Add to Cart
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task OnCardClicked()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task OnAddToCartClicked()
    {
        await OnAddToCart.InvokeAsync(Product);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        int empty = 5 - full;
        return new string('★', full) + new string('☆', empty);
    }
}

